import{_ as n,o as i,c as t,ag as r}from"./chunks/framework.DXGyWiRo.js";const a="/images/lekt1804.jpg",p="/images/lekt1801.jpg",o="/images/lekt1802.jpg",s="/images/lekt1803.jpg",k=JSON.parse('{"title":"Lektion 18","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion18.md","filePath":"lektionen/lektion18.md"}'),l={name:"lektionen/lektion18.md"};function u(d,e,h,m,g,b){return i(),t("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-18" tabindex="-1">Lektion 18 <a class="header-anchor" href="#lektion-18" aria-label="Permalink to &quot;Lektion 18&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>१. सुभाषितम्</li><li>18.2. Determinativkomposita (तत्पुरुष) mit adverbialem Vorderglied <ul><li>18.2.1. Komposita vom Typ सुकर / दुष्कर</li><li>18.2.2. Bedeutungen von nañ-Tatpuruṣa (a- / an-)</li></ul></li><li>18.3. Verbalkomposita <ul><li>18.3.1. Nominalbildungen zu Verbalkomposita</li></ul></li><li>18.4. Wortliste</li><li>18.5. Übung</li><li>18.6. Wiederholungsübung</li></ul><h2 id="१-सुभाषितम्" tabindex="-1">१. सुभाषितम् <a class="header-anchor" href="#१-सुभाषितम्" aria-label="Permalink to &quot;१. सुभाषितम्&quot;">​</a></h2><blockquote><p>नास्ति कामसमो व्याधिर्<br> नास्ति मोहसमो रिपुः ।<br> नास्ति क्रोधसमो वह्निर्<br> नास्ति ज्ञानसमं सुखम् ॥</p></blockquote><h2 id="_18-2-determinativkomposita-तत्पुरुष-mit-adverbialem-vorderglied" tabindex="-1">18.2. Determinativkomposita (तत्पुरुष) mit adverbialem Vorderglied <a class="header-anchor" href="#_18-2-determinativkomposita-तत्पुरुष-mit-adverbialem-vorderglied" aria-label="Permalink to &quot;18.2. Determinativkomposita (तत्पुरुष) mit adverbialem Vorderglied&quot;">​</a></h2><p>Als adverbiales (nichtdeklinierbares) Vorderglied können</p><ul><li>Adverbien</li><li>Präpositionen</li><li>Partikel</li><li>andere Indeklinabilia</li></ul><blockquote><p>verwendet werden. Solche Tatpurua gehören meist zur Klasse der Nityasamāsa = नित्यसमास (m. &quot;ständiges Kompisitum&quot;), d.h. der Komposita, die man überhaupt nicht oder nicht nur mittels der im Kompositum selbst vorkommenden Wörter auflösen kann.</p></blockquote><p>Beipiele:</p><p>अति &quot;darüber hinaus&quot;:</p><blockquote><p>अतिगुरु 3: überaus schwer, überaus gewichtig</p><p>अतिपुरुष m.: überragender Mann, Superman, Held</p><p>अतिस्तुति f.: übermäßiges Lob</p><p>अत्युक्ति f.: übermäßiges Sprechen, Übertreibung</p></blockquote><p>Die wichtigsten adverbialen Vorderglieder sind a-/an-, su-, dus-.</p><p>अ (vor Konsonant), अन् (vor Vokal): un-: steht im Kompositum anstelle von न &quot;nicht&quot;.</p><p>Beispiele:</p><blockquote><p>अनृत n. = नर्तम् (= न + ऋतम्): Unwahrheit, Lüge</p><p>अकृत 3 = न कृत 3: nicht getan, ungetan</p><p>अब्रआह्मणी f. = न ब्राह्मणी : eine Nichtbrahmanin, Unbrahmanin</p><p>अदेव m. = न देवः : ein Nichtgott, Ungott</p></blockquote><p>सु &quot;wohl, gut&quot;;  wird bei der Auflösung des Kompositums von den Kommentatoren durch ein Adjektiv mit der Bedeutung &quot;gut&quot; (z.B. सुष्टु 3, शोभन 3) ersetzt.</p><p>Beispiele:</p><blockquote><p>सुकवि m.: ein guter Dichter</p><p>सुकृत n.: gute Tat</p><p>सुखादित 3: gut gekaut</p><p>सुदुःख n.: großes Leid</p></blockquote><p>दुस् &quot;übel, schlecht&quot; (Sandhi beachten!).</p><p>Beispiele:</p><blockquote><p>दुर्नय m.: schlechte Führung, schlechtes Betragen</p><p>दुष्करण n.: schlechte Tat, schwierige Tat</p></blockquote><p>Dabei gilt folgendes Gesetz:</p><p>Lautveränderung von -s in Komposita</p><p>Entgegen dem Satzsandhi gilt im Auslaut des Vorderglieds von Komposita:</p><p>-s nach -i- oder -u- vor tonlosem Guttural oder Labial » -ṣ</p><p>Deshalb: दुष्करण</p><h3 id="_18-2-1-komposita-vom-typ-सुकर-दुष्कर" tabindex="-1">18.2.1. Komposita vom Typ सुकर / दुष्कर <a class="header-anchor" href="#_18-2-1-komposita-vom-typ-सुकर-दुष्कर" aria-label="Permalink to &quot;18.2.1. Komposita vom Typ सुकर / दुष्कर&quot;">​</a></h3><p>Komposita vom Typ सुकर / दुष्कर haben hauptsächlich die Bedeutung der passiven Möglichkeit:</p><p>Beispiele:</p><blockquote><p>सुकर 3: leicht zu tun</p><p>सुगम 3: leicht zu gehen</p><p>दुर्गम 3: schwer zu gehen</p><p>सुदुर्गम 3: sehr schwer zu gehen</p></blockquote><h3 id="_18-2-2-bedeutungen-von-nan-tatpurusa-a-an" tabindex="-1">18.2.2. Bedeutungen von nañ-Tatpuruṣa (a- / an-) <a class="header-anchor" href="#_18-2-2-bedeutungen-von-nan-tatpurusa-a-an" aria-label="Permalink to &quot;18.2.2. Bedeutungen von nañ-Tatpuruṣa (a- / an-)&quot;">​</a></h3><p>Tatpuruṣa mit a- / an- können folgende Bedeutungen haben:</p><ol><li>Ähnlichkeit (तत्सादृश्यम्):<br> अब्राह्मणः = ein Kṣatriya oder Vaiśya, der die heilige Schnur (यज्ञोपवीत n.) trägt und somit einem Brahmanen ähnelt, ohne einer zu sein</li><li>Fehlen, Nichtvvorhandensein (तदभावः):<br> अज्ञानम् = Unwissenheit (Fehlen von Wissen)</li><li>Andersheit (तदन्यत्वम्):<br> अपटम् = etwas, das kein Stoff / Gewand (पट m: Gewebe, Gewand) ist</li><li>Kleinheit (तदल्पता):<br> अनुदरम् = ein kleiner Bauch (ein Nicht-Bauch)</li><li>Missbilligung (अप्राशास्त्यम्):<br> अकालः = Unzeit</li><li>Feindschaft (निरोधः):<br> असुरः = Gegengott (nach der falschen Etymologie a-sura)</li></ol><p>Folgender Vers fasst diese Bedeutungen zusammen:</p><blockquote><p>तत्सादृश्यमभावश्च<br> तदन्यत्वं तदल्पता ।<br> अप्राशास्त्यं निरोधश्च<br> नजर्थाः षत्प्रकीर्तिताः ॥</p><p>Man nennt sechs Bedeutungen von nañ (= a-/an-) ....</p></blockquote><h2 id="_18-3-verbalkomposita" tabindex="-1">18.3. Verbalkomposita <a class="header-anchor" href="#_18-3-verbalkomposita" aria-label="Permalink to &quot;18.3. Verbalkomposita&quot;">​</a></h2><blockquote><p>उपसर्गेण धात्वर्थो<br> बलादन्यत्र नीयते ।<br> गङ्गासलिलमाधुर्यं<br> सागरेण यथाम्भसा ॥</p></blockquote><p>चन्द्रकीर्ति : प्रसन्नपदा S. 2 Zl. 14f.</p><p>Durch ein Präverb wird die Bedeutung einer Wurzel gewaltsam verändert, so wie die Süße des Gangeswassers durch Meerwasser.</p><p>Verben können im Sanskrit mit Präverben (उपसर्ग m.) verbunden werden. Dabei gilt meist der Satzsandhi. Präverbe können die Bedeutung der Wurzel u. U. bedeutend modifizieren, sodass in vielen Fällen die Bedeutung einer Wurzel mit Präverb gesondert gelernt werden muss. Verben mit Präverb können einen anderen Modus (P, Ā) haben als die einfache Wurzel. Vor eine Wurzel können gleichzeitig mehrere Präverbe gesetzt werden.</p><p>Einige wichtige Präverbe sind:</p><p>उप &quot;zu, hin, gegen&quot;</p><p>Beispiele:</p><blockquote><p>उपगम् 1 उपगच्छति : hingehen, darangehen</p><p>उपदिश् 6 उपदिशति : hinweisen, belehren, anraten</p><p>उपपद् 4 Ā उपपद्यते : hingelangen</p><blockquote><p>PPP उपपन्न 3: ausgestattet mit (Instrumentalis)</p></blockquote><p>उपलभ् 1 Ā उपलभते : erfassen, erlangen</p></blockquote><p>प्र &quot;vorwärts, hervor&quot;</p><p>Beispiele:</p><blockquote><p>प्राप्  (pra-āp) 5 प्राप्नोति : erlangen</p><p>प्रदिश् 6 प्रदिशति : zeigen</p><p>प्रबुध् 4 Ā प्रबुध्यते : aufwachen, erkennen</p><p>प्रभू 1 प्रभवति : hervorkommen, herausragen, Macht haben über (Gen., Lok. Dat.)</p><p>प्रवच् 2 प्रवक्ति PPP प्रोक्त (« pra + ukta) : erklären, mitteilen, aussprechen</p><p>प्रवद् 1 प्रवदति : aussprechen, bezeichnen als, erklären für</p><p>प्रस्तु 2 प्रस्तौति : preisen vor, laut preisen, auf etwas zu sprechen kommen, beginnen</p></blockquote><p>वि &quot;auseinander, weg, zer-, ver-&quot;</p><p>Beispiele:</p><blockquote><p>विगम् 1 विगच्छति : auseinandergehen, vergehen, verschwinden</p><p>विजि 1 Ā (!) विजयते : besiegen</p><p>विमुच् 6 विमुञ्चति : ablösen, befreien</p><p>विवद् 1 विवदति : disputieren, auseinandersetzen, erzählen</p><p>विस्मृ 1 विस्मरति : vergessen</p><p>विहन् 2 विहन्ति : zerschlagen, zerstören, vernichten</p></blockquote><p>सम् &quot;zusammen, mit&quot;</p><p>Beispiele:</p><blockquote><p>समास्  2 Ā समास्ते : zusammensitzen, sich aufhalten, wohnen</p><p>समि 2 समेति : zusammenkommen, sich vereinigen</p><p>संगम् 1 Ā (!) संगच्छते : zusammenkommen, aufeinandertreffen (freundlich oder feindlich), Geschlechtsverkehr haben mit (Akk.)</p><p>संजन् 4 Ā संजायते : entstehen</p><blockquote><p>PPP संजात 3: geboren, entstanden, geworden</p></blockquote><p>सम्बुध् 4 Ā सम्बुध्यते : vollständig erwachen (zur Wahrheit)</p><p>सम्पद् 4 Ā सम्पद्यते : jemandem zuteil werden, gelingen</p><blockquote><p>PPP सम्पन्न 3: versehen mit (Instr.)</p></blockquote></blockquote><p>Die Wurzel कृ &quot;tun&quot; zeigt in Verbindung mit den Präverben सम् । उप । अप । परि  auch die Form स्कृ</p><p>Beispiel:</p><blockquote><p>sam-kṛ 8 संस्करोति : zubereiten, fürs Opfer zubereiten, weihen</p><blockquote><p>PPP संस्कृत 3: fürs Opfer zubereitet ; संस्कृत n.: Sanskrit: die fürs Opfer geeignete Sprache ; Gegenstück प्राकृत 3: gewöhnlich, ordinär ; प्राकृत n.: gewöhnliche Sprache, Prakrit (Bezeichnung für die Volks- und Verkehrssprachen, die mit dem Sanskrit verwandt sind)</p></blockquote></blockquote><h3 id="_18-3-1-nominalbildungen-zu-verbalkomposita" tabindex="-1">18.3.1. Nominalbildungen zu Verbalkomposita <a class="header-anchor" href="#_18-3-1-nominalbildungen-zu-verbalkomposita" aria-label="Permalink to &quot;18.3.1. Nominalbildungen zu Verbalkomposita&quot;">​</a></h3><p>Von Wurzeln mit Präverben können mittels kṛt-Suffixen Nomina gebildet werden.</p><p>Beispiele:</p><p>sam-kṛ + -a = संस्कार m.: Weihe, Zubereitung ; Übergangsrituale = Bezeichnung für die Zeremonien, die die verschiedenen Lebensabschnitte von der Empfängnis bis zum Tod begleiten (s. dazu die ausgezeichnete Zusammenfassung bei Basha, Wonder S. 160 - 170!)</p><p><img src="'+a+'" alt=""><br> Abb.: Hochzeit = विवाह् m., ein wichtiger संस्कारः<br> [Bildquelle: Saad.Akhtar. -- <a href="http://www.flickr.com/photos/saad/64770385/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/saad/64770385/</a>. -- Zugriff am 2008-12-08. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>upa-nī + -ana = उपनयन n.: das Heranführen (ans Opferfeuer) = Zeremonie, bei der den männlichen Angehörigen der drei oberen Stände die heilige Schnur (यज्ञोपवीत n.) angelegt wird sowie der hl. Vers सावित्री ins Ohr geflüstert wird, den sie von nun an täglich bei Sonnenauf- und Sonnenuntergang rezitieren. Für die Brahmanen ist das Ṛgveda III.62.10:</p><blockquote><p>&quot;Mögen wir den vorzüglichen Glanz des Gottes &#39;Antreiber&#39; empfangen, der unsere Gedanken in Bewegung setzen möge.&quot;</p></blockquote><p>Durch das Upanayana geschieht die zweite Geburt, deshalb: द्विज । द्विजाति</p><p><img src="'+p+'" alt=""><br> Abb.: उपनयनम्</p><blockquote><p>&quot;A young boy is seen during upanayana ritual. The yellowed, thin, thread running from left shoulder to the waist is Yagnopaivta. Also note the girdle of munja grass around the waist. The twig in the right hand (usually from peepa treel) siginifies his entry in to Brahmacharya.&quot;</p><p>[Bildquelle: Nagesh Rao / Wikipedia, GNU FDLicense]</p></blockquote><h2 id="_18-4-wortliste" tabindex="-1">18.4. Wortliste <a class="header-anchor" href="#_18-4-wortliste" aria-label="Permalink to &quot;18.4. Wortliste&quot;">​</a></h2><p>सुष्टु 3: hochgepriesen, ausgezeichnet, gut</p><p>शोभन 3: glänzend, prächtig, herrlich, schön, gut</p><p>सम 3: gleich, eben, ähnlich (mit Instrumentalis)</p><p>व्याधि m.: Krankheit</p><p>रिपु m. =  शत्रु , Betrüger</p><p>वह्नि m. = अग्नि</p><p>ज्ञान n.: Erkenntnis</p><p>शूर 3: tapfer, heldenhaft ; m.: Held</p><p>शब्द m.: Laut, Ton, Signallaut: Wort</p><p>उदक n.: Wasser</p><p>अन्त m.: Ende, Grenze</p><p>आदि m.: Anfang</p><p>दण्ड m.: Stock, Prügel, Strafe</p><p>मात्रा f. मात्र n.: Maß, Begrenzung</p><p>सहित 3: vereinigt, versehen mit</p><p>हस्त m.: Hand</p><p>प्रभृति f.: Anfang</p><h2 id="_18-5-ubung" tabindex="-1">18.5. Übung <a class="header-anchor" href="#_18-5-ubung" aria-label="Permalink to &quot;18.5. Übung&quot;">​</a></h2><p>A) Übersetzen Sie das सुभाषित am Beginn der Lektion.</p><p>B) Übersetzen Sie folgende Tatpuruṣa:</p><p>१. सुकर ३</p><p>२. सुकुल n.</p><p>३. सुकृति f.</p><p>४. अकरण n.</p><p>५. दुरिष्ट n.</p><p>६. दुरिष्टि f.</p><p>७. सुखादित 3</p><p>८. दुष्कर 3</p><p>९. दुर्जय 3</p><p>१०. सुगत m.</p><p>११. सुजन m.</p><p>१२. दुरुक्ति f.</p><p>१३. दुरुपदेश m.</p><p>१४. सुजात 3</p><p>१५. सुगुरु 3</p><p>१६. अनाप्त 3</p><p>१७. अनीति f.</p><p>१८. अनीश्वरत्व n.</p><p>१९. सुदुःख n.</p><p>२०. दुर्जन m.</p><p>२१. दुर्दग्ध 3</p><p>२२. अतिकृत 3</p><p>२३. सुपुत्र m.</p><p>२४. सुबुद्धि f.</p><p>२५. दुष्पुत्र m.</p><p>२६. दुष्प्रणीत 3</p><p>२७. सुमति f.</p><p>२८. दुर्लभ 3</p><p>२९. दुर्वच 3</p><p>३०. दुर्वचन n.</p><p>३१. अमृत n.</p><h2 id="_18-6-wiederholungsubung" tabindex="-1">18.6. Wiederholungsübung <a class="header-anchor" href="#_18-6-wiederholungsubung" aria-label="Permalink to &quot;18.6. Wiederholungsübung&quot;">​</a></h2><p>Bitte keine Hilfsmittel benutzen!</p><p>A) Lösen Sie folgende Komposita in Sanskrit auf und geben Sie Übersetzungsvorschläge:</p><p>१. अन्तगत 3</p><p>२. क्षमाकर 3</p><p>३. क्षेमेन्द्र m.</p><p>४. शस्त्रकोपनिरोध m.</p><p>५. सिंहसंहनन n.</p><p>६. अरिसिंह m.</p><p>७. आहारनिद्राभय n.</p><p>८. मृतिसाधनी f.</p><p>९. कुलोपदेश m.</p><p><img src="'+o+'" alt=""><br> Abb.: मृतिसाधनी काली<br> 1770 Print<br> [Bildquelle: Wikipedia, Public domain]</p><p>B) Übersetzen Sie unter Verwendung von Verben der 2. Präsensklasse:</p><p>1. Der Brahmane preist die Göttinnen.</p><p>2. Die Helden gehen auf dem schwer begehbaren Weg ins Dorf der Arier.</p><p>3. Die Hausmagd melkt die Kühe.</p><p>4. Die Feinde der Arier erschlagen die mächtigen Kṣatriyas.</p><p>5. Ein Gespenst isst keine Früchte.</p><p>6. So spricht der, der [den Weg durch die Wiedergeburten] gut gegangen ist zum Jünger.</p><p><img src="'+s+'" alt=""><br> Abb.: सुगतः<br> गन्धार 1./2. Jhdt. n. Chr.<br> [Bildquelle: Wikipedia, Public domain]</p><p>C) Geben Sie in Sanskrit die Definition von Yoga auf zwei Weisen: einmal unter Verwendung eines Kompositums, einmal indem Sie das Kompositum auflösen.</p><p>D) Übersetzen Sie:</p><p>(धर्मः) सर्वेषामाहिंसा सत्यं शौचमनसूयानृशंस्यं क्षमा च ॥</p>',144)])])}const f=n(l,[["render",u]]);export{k as __pageData,f as default};
